-- ------------------------------------------------------------
-- 3. ЛИДЫ
--    name    — контактное лицо
--    company — юр. лицо (NULL если физлицо)
-- ------------------------------------------------------------
CREATE TABLE leads (
    id         SERIAL       PRIMARY KEY,
    name       VARCHAR(150) NOT NULL,
    company    VARCHAR(200),
    phone      VARCHAR(30)  NOT NULL,
    email      VARCHAR(150),
    source     VARCHAR(20)  NOT NULL DEFAULT 'other'
                            CHECK (source IN ('form', 'call', 'chat', 'other')),
    subject    VARCHAR(200),
    notes      TEXT,
    status     VARCHAR(20)  NOT NULL DEFAULT 'new'
                            CHECK (status IN ('new', 'contacted', 'in_work', 'closed')),
    manager_id INT          REFERENCES managers(id) ON DELETE SET NULL,
    created_at TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

